<template>
  <div class="container">
    <Navbar />
    <div class="row">
      <div class="col-md-8 offset-md-2">
        <h3 class="mb-4 text-center">我的课表</h3>
        <!-- 课表卡片 -->
        <div class="card border-primary">
          <div class="card-header bg-primary text-white">
            今日课表（{{ getWeekday() }}）
          </div>
          <div class="card-body">
            <table class="table table-sm table-hover">
              <thead>
                <tr>
                  <th>课程名称</th>
                  <th>上课时间</th>
                  <th>上课地点</th>
                </tr>
              </thead>
              <tbody>
                <tr v-for="(item, index) in scheduleList" :key="index">
                  <td>{{ item.courseName }}</td>
                  <td>{{ item.time }}</td>
                  <td>{{ item.place }}</td>
                </tr>
                <tr v-if="scheduleList.length === 0">
                  <td colspan="3" class="text-center text-muted">今日无课，好好休息～</td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import Navbar from '../components/Navbar.vue'
export default {
  name: 'Schedule',
  components: { Navbar },
  data() {
    return {
      scheduleList: [], // 课表列表
      userId: this.$cookies.get('userId') || 1 // 从Cookies获取用户ID
    }
  },
  mounted() {
    this.getTodaySchedule()
  },
  methods: {
    // 获取今日课表
    async getTodaySchedule() {
      try {
        const res = await this.$axios.get('/schedule/today', {
          params: { userId: this.userId }
        })
        if (res.data.code === 200) {
          this.scheduleList = res.data.data
        }
      } catch (err) {
        console.error(err)
        this.$message && this.$message.error('查询课表失败！')
      }
    },
    // 获取当前星期几
    getWeekday() {
      const weekday = ['周日', '周一', '周二', '周三', '周四', '周五', '周六']
      return weekday[new Date().getDay()]
    }
  }
}
</script>
